#!/bin/bash
set -euo pipefail
export LANG=en_US.UTF-8
YW='\033[33m'; GN='\033[1;92m'; RD='\033[01;31m'; CL='\033[m'
BFR="\\r\\033[K"; CM="${GN}✓${CL}"; TAB="  "
msg_info() { printf "${TAB}${YW}[ .. ]${CL} %s..." "$1"; }
msg_ok()   { printf "${BFR}${TAB}${CM} %s\n" "$1"; }
INSTALL_DIR="/opt/streamforge"; SERVICE_USER="streamforge"
echo -e "\n${YW}StreamForge Updater${CL}\n"
msg_info "Stopping StreamForge"; systemctl stop streamforge; msg_ok "Stopped"
msg_info "Updating index.js";    echo ''  | base64 -d > "$INSTALL_DIR/server/index.js";    msg_ok "Done"
msg_info "Updating package.json";echo ''  | base64 -d > "$INSTALL_DIR/server/package.json";msg_ok "Done"
msg_info "Updating index.html";  echo '' | base64 -d > "$INSTALL_DIR/public/index.html";  msg_ok "Done"
msg_info "Updating main.css";    echo ''  | base64 -d > "$INSTALL_DIR/public/css/main.css";msg_ok "Done"
msg_info "Updating app.js";      echo ''   | base64 -d > "$INSTALL_DIR/public/js/app.js";   msg_ok "Done"
msg_info "Fixing ownership"; chown -R "$SERVICE_USER:$SERVICE_USER" "$INSTALL_DIR"; msg_ok "Done"
msg_info "Updating npm deps"
su -s /bin/bash "$SERVICE_USER" -c "cd $INSTALL_DIR/server && npm install --production --quiet"
msg_ok "Done"
msg_info "Starting StreamForge"; systemctl start streamforge; sleep 3
if systemctl is-active --quiet streamforge; then
  msg_ok "StreamForge running"
else
  node "$INSTALL_DIR/server/index.js" 2>&1 | head -15
  exit 1
fi
echo -e "\n${GN}Update complete!${CL}"
echo "Go to Settings to configure transcoding options."
echo ""
